import { setBit, clearBit, toggleBit, hasBit, countBits, isPowerOf2 } from '../src/bitUtils'

let failures = 0
async function check(name: string, got: unknown, want: unknown) {
  got = await got  // resolve promises transparently
  const ok = JSON.stringify(got) === JSON.stringify(want)
  console.log(`  ${ok ? 'PASS' : 'FAIL'} — ${name}`)
  if (!ok) {
    console.log(`       got:  ${JSON.stringify(got)}`)
    console.log(`       want: ${JSON.stringify(want)}`)
    failures++
  }
}

;(async () => {
await check("setBit", setBit(0b1010, 0), 11)
await check("clearBit", clearBit(0b1010, 1), 8)
await check("toggleBit set", toggleBit(0, 2), 4)
await check("toggleBit clear", toggleBit(4, 2), 0)
await check("hasBit true", hasBit(0b1010, 1), true)
await check("hasBit false", hasBit(0b1010, 0), false)
await check("countBits 7", countBits(7), 3)
await check("countBits 0", countBits(0), 0)
await check("isPowerOf2 true", isPowerOf2(16), true)
await check("isPowerOf2 false", isPowerOf2(6), false)
await check("isPowerOf2 zero", isPowerOf2(0), false)
console.log(failures === 0 ? 'ALL PASS' : `${failures} FAILURE(S)`)
process.exit(failures === 0 ? 0 : 1)
})()
